// MARK: - Exception Handling
fileprivate func nscalc_throwException(buffer: FlatBuffer) -> any Error {
  guard let data = buffer.constData else {
    return RuntimeError(message: "Failed to read exception data")
  }
  let exId = data.load(fromByteOffset: 16, as: UInt32.self)
  switch exId {
  case 0:
    return unmarshal_AuthorizationFailed(buffer: data, offset: 16)
  case 1:
    return unmarshal_RegistrationFailed(buffer: data, offset: 16)
  case 2:
    return unmarshal_PermissionViolation(buffer: data, offset: 16)
  case 3:
    return unmarshal_InvalidArgument(buffer: data, offset: 16)
  default:
    return RuntimeError(message: "Unknown exception id: \(exId)")
  }
}
